UPDATE party_operation
SET
    operation_status = #{operationStatus},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE party_operation
SET
    operation_status = #{operationStatus},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND operation_status <> 'ACTIVE'

UPDATE party_operation
SET
    operation_status = #{operationStatus},
    operation_completed_at = #{operationCompletedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
